                rows_data = []
                for _, elem in ET.iterparse(f, events=('end',)):
                    if elem.tag != f'{{{ns}}}row':
                        continue
                    values = {}
                    for cell in elem.findall(f'{{{ns}}}c'):
                        m = re.match(r'^[A-Z]+', cell.get('r',''))
                        if m:
                            col = m.group(0)
                            if cell.get('t') == 'inlineStr':
                                t = ''.join(node.text or '' for node in cell.iter(f'{{{ns}}}t'))
                            else:
                                v = cell.find(f'{{{ns}}}v')
                                t = v.text if v is not None and v.text is not None else ''
                            values[col] = t
                    rows_data.append(values)
                    elem.clear()
            if rows_data:
                print('Header row:', rows_data[0])
                print()
